def solve(frequencies, track):
    if not isinstance(frequencies, list) or not all(isinstance(f, (int, float)) for f in frequencies):
        raise ValueError("Frequencies must be a list of numbers.")

    if not isinstance(track, list) or not all(isinstance(note, (int, float)) for note in track):
        raise ValueError("Track must be a list of numbers.")

    # Embed frequencies into the track
    for freq in frequencies:
        track.append(freq)

    return track
